const body = $input.item.json.body || $input.item.json;
const mode = body.mode || 'ico';
const ico = (body.ico || '').trim();
const website = (body.website || '').trim();
const first_name = (body.first_name || '').trim();
const last_name = (body.last_name || '').trim();
const email = (body.email || '').trim();

// Extract clean domain from website (or from email for verify mode)
let domain = website.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0].trim();
if (!domain && email) domain = email.split('@')[1] || '';

return {
  json: { mode, ico, website, first_name, last_name, email, domain }
};

const domain = $('Extract Input').first().json.domain;
const ico = $('Extract Input').first().json.ico;

const resp = $input.item.json;
const html = (resp.body || resp.data || '') + '';

if (!html || html.length < 100) {
  return { json: { jednatels: [], domain } };
}

const jednatels = [];
const seen = new Set();

// Strategy 1: <b>Jednatel</b> then <a href="/osoba/N/">NAME</a>
const kurzyPattern = /<(?:b|strong)[^>]*>[\s\n]*Jednatel[\s\n]*<\/(?:b|strong)>[\s\S]{0,600}?<a[^>]*href="\/osoba\/\d+\/[^"]*"[^>]*>([^<]+)/gi;
let m;
while ((m = kurzyPattern.exec(html)) !== null) {
  const raw = m[1].trim();
  if (raw.length < 3 || raw.length > 100 || seen.has(raw.toLowerCase())) continue;
  seen.add(raw.toLowerCase());
  const cleaned = raw.replace(/^(Ing\.|Mgr\.|Bc\.|JUDr\.|MUDr\.|PhDr\.|Doc\.|Prof\.|RNDr\.|DiS\.)\s*/gi, '').trim();
  const parts = cleaned.split(/\s+/);
  if (parts.length < 2) continue;
  jednatels.push({ first_name: parts[0], last_name: parts[parts.length - 1] });
}

// Strategy 2: generic TD pattern
if (jednatels.length === 0) {
  const tdPattern = /<td[^>]*>[^<]*jednatel[^<]*<\/td>\s*<td[^>]*>([^<]+)<\/td>/gi;
  while ((m = tdPattern.exec(html)) !== null) {
    const raw = m[1].trim();
    if (raw.length < 3 || raw.length > 100 || seen.has(raw.toLowerCase())) continue;
    seen.add(raw.toLowerCase());
    const cleaned = raw.replace(/^(Ing\.|Mgr\.|Bc\.|JUDr\.|MUDr\.|PhDr\.)\s*/gi, '').trim();
    const parts = cleaned.split(/\s+/);
    if (parts.length < 2) continue;
    jednatels.push({ first_name: parts[0], last_name: parts[parts.length - 1] });
  }
}

// Strategy 3: Statutární orgán section
if (jednatels.length === 0) {
  const sectionMatch = html.match(/Statutárn[íi] orgán[\s\S]*?(?=<h[1-4]|<\/section)/i);
  if (sectionMatch) {
    const section = sectionMatch[0];
    const namePattern = /<strong>([^<]{5,60})<\/strong>/g;
    while ((m = namePattern.exec(section)) !== null) {
      const raw = m[1].trim();
      if (seen.has(raw.toLowerCase())) continue;
      seen.add(raw.toLowerCase());
      const cleaned = raw.replace(/^(Ing\.|Mgr\.|Bc\.|JUDr\.|MUDr\.)\s*/gi, '').trim();
      const parts = cleaned.split(/\s+/);
      if (parts.length < 2) continue;
      jednatels.push({ first_name: parts[0], last_name: parts[parts.length - 1] });
    }
    if (jednatels.length === 0) {
      const osobaPattern = /<a[^>]*href="\/osoba\/\d+\/[^"]*"[^>]*>([^<]+)<\/a>/gi;
      while ((m = osobaPattern.exec(section)) !== null) {
        const raw = m[1].trim();
        if (raw.length < 3 || raw.length > 100 || seen.has(raw.toLowerCase())) continue;
        seen.add(raw.toLowerCase());
        const cleaned = raw.replace(/^(Ing\.|Mgr\.|Bc\.|JUDr\.|MUDr\.|PhDr\.|Doc\.|Prof\.|RNDr\.|DiS\.)\s*/gi, '').trim();
        const parts = cleaned.split(/\s+/);
        if (parts.length < 2) continue;
        jednatels.push({ first_name: parts[0], last_name: parts[parts.length - 1] });
      }
    }
  }
}

return { json: { jednatels, domain } };

const domain = $('Extract Input').first().json.domain;
const first_name = $('Extract Input').first().json.first_name;
const last_name  = $('Extract Input').first().json.last_name;
const jednatels = (first_name || last_name) ? [{ first_name, last_name }] : [];
return { json: { jednatels, domain } };

const items = $input.all();
const { jednatels, domain } = items[0].json;

function norm(s) {
  return (s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

const candidates = [];

for (const j of jednatels) {
  const f = norm(j.first_name);
  const l = norm(j.last_name);
  if (!f && !l) continue;
  if (f && l) {
    candidates.push({ email_address: `${f}.${l}@${domain}`, source: 'personal' });
    candidates.push({ email_address: `${f[0]}.${l}@${domain}`, source: 'personal' });
    candidates.push({ email_address: `${f}@${domain}`, source: 'personal' });
    candidates.push({ email_address: `${f}${l}@${domain}`, source: 'personal' });
  } else if (l) {
    candidates.push({ email_address: `${l}@${domain}`, source: 'personal' });
  } else if (f) {
    candidates.push({ email_address: `${f}@${domain}`, source: 'personal' });
  }
}

for (const local of ['info', 'kontakt', 'hello', 'admin']) {
  candidates.push({ email_address: `${local}@${domain}`, source: 'generic' });
}

const seen = new Set();
const unique = candidates.filter(c => {
  if (seen.has(c.email_address)) return false;
  seen.add(c.email_address);
  return true;
});

return unique.map(c => ({ json: { ...c, domain } }));

const items = $input.all();
const inputData = $('Extract Input').first().json;
const results = [];

function deriveStatus(d) {
  if (!d.has_mx) return 'invalid';
  if (d.smtp_result === 'invalid') return 'invalid';
  if (d.smtp_result === 'valid' && !d.is_catch_all) return 'valid';
  if (d.smtp_result === 'valid' && d.is_catch_all) return 'likely_valid';
  if (d.is_valid) return 'likely_valid';
  if (['timeout','error','skipped','unknown'].includes(d.smtp_result)) return 'unknown';
  return 'unknown';
}

function deriveConfidence(score) {
  if (score >= 70) return 'high';
  if (score >= 40) return 'medium';
  return 'low';
}

for (const item of items) {
  const d = item.json;
  const email = d.email || d.email_address || '';
  if (!email) continue;
  const status = deriveStatus(d);
  const confidence = deriveConfidence(d.confidence_score || 0);
  results.push({ email, status, confidence, smtp_result: d.smtp_result || null });
}

const order = { valid: 0, likely_valid: 1, unknown: 2, invalid: 3 };
results.sort((a, b) => (order[a.status] ?? 5) - (order[b.status] ?? 5));

const domain = inputData.domain || (results[0]?.email?.split('@')[1] || '');

return [{ json: { candidates: results, domain, total: results.length } }];
